INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0489de64-moex-00141', 'elementary-0489de64', 'elementary-0489de64-moex-114-34c7f7f6', 'sub-elementary-0489de64-03', NULL, 'single_choice', '「番薯是原產於拉丁美洲的作物。日文裡的番薯稱為『薩摩芋』，意即來自薩摩地區，這個 稱呼主要在日本的本州以北使用，在北九州則有『琉球芋』之稱，可是南九州、沖繩又以『唐 芋』稱呼。同樣在中國，浙東地區士大夫編纂地方誌時，就舉出『番芋』是舟山群島的特產 之一，並在說明『味甚甘美』的同時，也記載了『種來自日本』，而番薯的『番』是指日本。」 根據上文，下列選項何者符合文意？', '["番薯雖原產於拉丁美洲，但在亞洲成為重要的主食", "日本的本州與南北九州，對番薯有三種不同的稱呼", "沖繩對番薯的說法差異，主要是受到經濟文化影響", "人們對番薯的各種稱呼，反映對其來源的不同看法 番薯應是舟山群島特產，但中國士人以為來自日本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:57+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00142', 'elementary-0489de64', 'elementary-0489de64-moex-114-34c7f7f6', 'sub-elementary-0489de64-03', NULL, 'single_choice', '古人曾言「所種者穀，雖瘠土墮農，不生稗也；所種者稗，雖美田疾耕，不生穀也。」 根據上文，下列選項何者符合文意？', '["水到渠成，不須預慮", "江山易改，本性難移", "種瓜得瓜，種豆得豆", "貧不學儉，富不學奢 蓬生麻中，不扶自直"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:57+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00143', 'elementary-0489de64', 'elementary-0489de64-moex-114-34c7f7f6', 'sub-elementary-0489de64-03', NULL, 'single_choice', '落日千林紫，漁舟聚淺灘。飛蓬雲外沒，野鳥望中還。寺小藏深樹，潮寬點亂山。一樽頻對 此，無意羨人間。（宋懋澄〈晚色〉） 根據上詩，下列敘述何者正確？', '["刻畫景物，藉景抒情", "蘊含瀟灑的出世之想", "充滿山水意趣，富有情韻", "描寫晚景，宛如一幅山水畫卷 近似「夕陽無限好，只是近黃昏」之意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:57+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00144', 'elementary-0489de64', 'elementary-0489de64-moex-114-34c7f7f6', 'sub-elementary-0489de64-03', NULL, 'single_choice', '「畫家在素描時，勒定了所畫對象大約的輪廓後，只以炭筆磨擦出光影的陰暗與明亮，而不 做細部的描繪，保持一點朦朧感，以免整個畫面過於呆板。這個階段，就像詩一樣，在光與 暗、有與無之間，帶著一點迷濛，一點神祕，一點耐人追索的況味。然而這並非脫離現實， 仔細想想，我們在人生裡，大多數的情感都是這樣迷濛的吧！誰能肯定自己的內心無論是哪 一刻都清晰無比的呢？」 根據上文，下列選項正確的是：', '["擅長讀詩的人擁有最單純的心思，對世事經常感到懵懵懂懂", "詩在指涉、內涵上的模糊性，常能帶給讀者解釋探索的趣味", "詩與素描一樣，都不可進行細部描繪，才能提升整體的美感", "思緒清明的人難以享受讀詩之樂，因複雜處能輕易迎刃而解 生命中多數情感一如詩般迷濛，從詩中可以體會人生與現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:57+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00145', 'elementary-0489de64', 'elementary-0489de64-moex-114-34c7f7f6', 'sub-elementary-0489de64-03', NULL, 'single_choice', '「ChatGPT或Bing Chat多是提供定義式的短語，回覆的內容主要是『已知』的有限資訊， 難以『多義性』的語言表現感知複雜的人類思維。這是因為 AI 的訓練出自設計者目前的偏 好或定見，如果想讓AI更貼近人類需求，就必須仰賴人類持續更新且多樣化的經驗。」 根據上文，下列選項正確的是：', '["目前AI程式設計者偏好取樣多元的生活經驗", "AI現在仍未取代人類思想情感的複雜性表現", "AI設計者皆偏愛不受感知影響的科學性語言", "目前AI是以短語提供快速單一的資訊為目的 不斷轉型的語言文化和科技趨勢無直接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:57+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00146', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '運輸行為源於通勤（工作、求學）、購物、遊憩休閒、訪遊探親、商務與個人事務等活動或貨物運送， 請問何者不在運輸學中討論？', '["從高雄捷運五塊厝站搭乘高雄捷運到美麗島站上班", "前往屏東墾丁海灘騎乘水上摩托車", "從臺北車站搭乘高鐵到新竹六家站，轉搭計程車到竹科拜訪客戶", "從板橋搭乘捷運板南線從亞東醫院站到臺北車站，轉捷運信義線到臺北101站到華納威秀看電影"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00147', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '113 年 4 月花蓮強震導致東部鐵公路受損，交通部航港局緊急調度臺北快輪及新台馬輪投入蘇花海 運備援，執行車輛載運，請問屬何種「複合運輸」之類型？', '["鐵路與水路聯運", "公路與水路聯運", "公路與空運聯運", "鐵路與公路聯運"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00148', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '宜靜早上7：00從家步行580公尺（8分鐘）到吳興國小公車站，等公車花了10分鐘，上車後公車 經14站（16分鐘）抵達南京復興站，然後步行230公尺（4分鐘），到達敦化國中，請計算這趟就 學旅次之車外時間為多少？', '["18分鐘", "22分鐘", "34分鐘", "38分鐘"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00149', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '鐵路車站各項設施如：①出入大廳  ②行李房  ③服務台  ④警駐所  ⑤急救室  ⑥餐廳  ⑦末軌 式月台  ⑧列車調度場  ⑨儲車場  ⑩控制中心等，請選出下列為列車調度功能所需之項目：', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00150', 'elementary-0489de64', 'elementary-0489de64-moex-114-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '欲改善國內交通問題，必須朝向抑制私人運具成長及鼓勵大眾運輸發展同時進行，才能發揮具體功 效，請選出屬於「推」的策略：', '["引進大眾捷運系統，並整合大眾運輸", "引進智慧型大眾運輸系統，以疏導運輸需求", "由汽車燃料使用費，提撥固定比例補貼大眾運輸", "管制機動車輛之成長與使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "6cd7e3b3ae37", "answer_pdf_sha1": "75423ee3daf4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "515", "s": "0405", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
